void bpnn_layerforward_openmp(float *l1, float *l2, float **conn, int n1, int n2) {
  float sum;
  int j, k;

  l1[0] = 1.0;

  omp_set_num_threads(NUM_THREAD);
  #pragma omp parallel for shared(conn, n1, n2, l1, l2) private(k, j, sum) schedule(static)
  for (j = 1; j <= n2; j++) {
    sum = 0.0;
    for (k = 0; k <= n1; k++) {
      sum += conn[k][j] * l1[k];
    }
    l2[j] = squash(sum);
  }
}

void bpnn_adjust_weights_openmp(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
  float new_dw;
  int k, j;

  ly[0] = 1.0;

  omp_set_num_threads(NUM_THREAD);
  #pragma omp parallel for shared(oldw, w, delta, ly) private(j, k, new_dw) schedule(static)
  for (j = 1; j <= ndelta; j++) {
    for (k = 0; k <= nly; k++) {
      new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
  }
}

