#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void calculate_temp(int iteration,  
                    float *power,   
                    float *temp_src,    
                    float *temp_dst,    
                    int grid_cols,  
                    int grid_rows,  
                    int border_cols,  
                    int border_rows,  
                    float Cap,      
                    float Rx, 
                    float Ry, 
                    float Rz, 
                    float step, 
                    float time_elapsed,
                    float *temp_on_cuda,
                    float *power_on_cuda,
                    float *temp_t){

	float step_div_Cap;
    float Rx_1,Ry_1,Rz_1;

	int bx = 0;
    int by = 0;

	int tx=0;
	int ty=0;

	step_div_Cap=step/Cap;

	Rx_1=1/Rx;
	Ry_1=1/Ry;
	Rz_1=1/Rz;


	int small_block_rows = BLOCK_SIZE-iteration*2;
	int small_block_cols = BLOCK_SIZE-iteration*2;


        int blkY = small_block_rows*by-border_rows;
        int blkX = small_block_cols*bx-border_cols;
        int blkYmax = blkY+BLOCK_SIZE-1;
        int blkXmax = blkX+BLOCK_SIZE-1;


	int yidx = blkY+ty;
	int xidx = blkX+tx;


	int loadYidx=yidx, loadXidx=xidx;
        int index = grid_cols*loadYidx+loadXidx;

	if(IN_RANGE(loadYidx, 0, grid_rows-1) && IN_RANGE(loadXidx, 0, grid_cols-1)){
            temp_on_cuda[ty*BLOCK_SIZE+tx] = temp_src[index];  
            power_on_cuda[ty*BLOCK_SIZE+tx] = power[index];
	}



        int validYmin = (blkY < 0) ? -blkY : 0;
        int validYmax = (blkYmax > grid_rows-1) ? BLOCK_SIZE-1-(blkYmax-grid_rows+1) : BLOCK_SIZE-1;
        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > grid_cols-1) ? BLOCK_SIZE-1-(blkXmax-grid_cols+1) : BLOCK_SIZE-1;

        int N = ty-1;
        int S = ty+1;
        int W = tx-1;
        int E = tx+1;

        N = (N < validYmin) ? validYmin : N;
        S = (S > validYmax) ? validYmax : S;
        W = (W < validXmin) ? validXmin : W;
        E = (E > validXmax) ? validXmax : E;

        bool computed;
        for (int i=0; i<iteration ; i++){ 
            computed = false;
            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) &&  \
                  IN_RANGE(ty, i+1, BLOCK_SIZE-i-2) &&  \
                  IN_RANGE(tx, validXmin, validXmax) && \
                  IN_RANGE(ty, validYmin, validYmax) ) {
                  computed = true;
                  temp_t[ty*BLOCK_SIZE+tx] =   temp_on_cuda[ty*BLOCK_SIZE+tx] + step_div_Cap * (power_on_cuda[ty*BLOCK_SIZE+tx] + 
		         (temp_on_cuda[S*BLOCK_SIZE+tx] + temp_on_cuda[N*BLOCK_SIZE+tx] - 2.0*temp_on_cuda[ty*BLOCK_SIZE+tx]) * Ry_1 + 
		             (temp_on_cuda[ty*BLOCK_SIZE+E] + temp_on_cuda[ty*BLOCK_SIZE+W] - 2.0*temp_on_cuda[ty*BLOCK_SIZE+tx]) * Rx_1 + 
		             (amb_temp - temp_on_cuda[ty*BLOCK_SIZE+tx]) * Rz_1);

            }
            if(i==iteration-1)
                break;
            if(computed)	 
                temp_on_cuda[ty*BLOCK_SIZE+tx]= temp_t[ty*BLOCK_SIZE+tx];
          }


      if (computed){
          temp_dst[index]= temp_t[ty*BLOCK_SIZE+tx];		
      }
}

void calculate_temp_parallel(int iteration,  
                               float *power,   
                               float *temp_src,    
                               float *temp_dst,    
                               int grid_cols,  
                               int grid_rows,  
                               int border_cols,  
                               int border_rows,  
                               float Cap,      
                               float Rx, 
                               float Ry, 
                               float Rz, 
                               float step, 
                               float time_elapsed){

        float *temp_on_cuda = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
        float *power_on_cuda = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
        float *temp_t = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float)); 

	float amb_temp = 80.0;
        float step_div_Cap;
        float Rx_1,Ry_1,Rz_1;

	step_div_Cap=step/Cap;

	Rx_1=1/Rx;
	Ry_1=1/Ry;
	Rz_1=1/Rz;


	int small_block_rows = BLOCK_SIZE-iteration*2;
	int small_block_cols = BLOCK_SIZE-iteration*2;

        int blockRows = grid_rows/small_block_rows+((grid_rows%small_block_rows==0)?0:1);
        int blockCols = grid_cols/small_block_cols+((grid_cols%small_block_cols==0)?0:1);

#pragma omp parallel for collapse(2)
        for (int by = 0; by < blockRows; by++) {
            for (int bx = 0; bx < blockCols; bx++) {

                int blkY = small_block_rows*by-border_rows;
                int blkX = small_block_cols*bx-border_cols;
                int blkYmax = blkY+BLOCK_SIZE-1;
                int blkXmax = blkX+BLOCK_SIZE-1;


                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {

                        int yidx = blkY+ty;
                        int xidx = blkX+tx;


                        int loadYidx=yidx, loadXidx=xidx;
                        int index = grid_cols*loadYidx+loadXidx;

                        if(IN_RANGE(loadYidx, 0, grid_rows-1) && IN_RANGE(loadXidx, 0, grid_cols-1)){
                            temp_on_cuda[ty*BLOCK_SIZE+tx] = temp_src[index];  
                            power_on_cuda[ty*BLOCK_SIZE+tx] = power[index];
                        }
                    }
                }



                int validYmin = (blkY < 0) ? -blkY : 0;
                int validYmax = (blkYmax > grid_rows-1) ? BLOCK_SIZE-1-(blkYmax-grid_rows+1) : BLOCK_SIZE-1;
                int validXmin = (blkX < 0) ? -blkX : 0;
                int validXmax = (blkXmax > grid_cols-1) ? BLOCK_SIZE-1-(blkXmax-grid_cols+1) : BLOCK_SIZE-1;

                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {

                        int N = ty-1;
                        int S = ty+1;
                        int W = tx-1;
                        int E = tx+1;

                        N = (N < validYmin) ? validYmin : N;
                        S = (S > validYmax) ? validYmax : S;
                        W = (W < validXmin) ? validXmin : W;
                        E = (E > validXmax) ? validXmax : E;

                        bool computed;
                        for (int i=0; i<iteration ; i++){ 
                            computed = false;
                            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) &&  \
                                  IN_RANGE(ty, i+1, BLOCK_SIZE-i-2) &&  \
                                  IN_RANGE(tx, validXmin, validXmax) && \
                                  IN_RANGE(ty, validYmin, validYmax) ) {
                                  computed = true;
                                  temp_t[ty*BLOCK_SIZE+tx] =   temp_on_cuda[ty*BLOCK_SIZE+tx] + step_div_Cap * (power_on_cuda[ty*BLOCK_SIZE+tx] + 
	                                 (temp_on_cuda[S*BLOCK_SIZE+tx] + temp_on_cuda[N*BLOCK_SIZE+tx] - 2.0*temp_on_cuda[ty*BLOCK_SIZE+tx]) * Ry_1 + 
			                         (temp_on_cuda[ty*BLOCK_SIZE+E] + temp_on_cuda[ty*BLOCK_SIZE+W] - 2.0*temp_on_cuda[ty*BLOCK_SIZE+tx]) * Rx_1 + 
			                         (amb_temp - temp_on_cuda[ty*BLOCK_SIZE+tx]) * Rz_1);

                            }
                            if(i==iteration-1)
                                break;
                            if(computed)	 
                                temp_on_cuda[ty*BLOCK_SIZE+tx]= temp_t[ty*BLOCK_SIZE+tx];
                          }



                          if (computed){
                              int yidx = blkY+ty;
                              int xidx = blkX+tx;
                              int index = grid_cols*yidx+xidx;
                              if(IN_RANGE(yidx, 0, grid_rows-1) && IN_RANGE(xidx, 0, grid_cols-1)){
                                  temp_dst[index]= temp_t[ty*BLOCK_SIZE+tx];		
                              }
                          }
                    }
                }
            }
        }

        free(temp_on_cuda);
        free(power_on_cuda);
        free(temp_t);
}





int compute_tran_temp(float *MatrixPower,float *MatrixTemp[2], int col, int row, \
		int total_iterations, int num_iterations, int blockCols, int blockRows, int borderCols, int borderRows) 
{

	float grid_height = chip_height / row;
	float grid_width = chip_width / col;

	float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
	float Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
	float Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
	float Rz = t_chip / (K_SI * grid_height * grid_width);

	float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
	float step = PRECISION / max_slope;
	float t;
        float time_elapsed;
	time_elapsed=0.001;

        int src = 1, dst = 0;

	for (t = 0; t < total_iterations; t+=num_iterations) {
            int temp = src;
            src = dst;
            dst = temp;
            calculate_temp_parallel(MIN(num_iterations, total_iterations-t), MatrixPower,MatrixTemp[src],MatrixTemp[dst],\
		col,row,borderCols, borderRows, Cap,Rx,Ry,Rz,step,time_elapsed);
	}
        return dst;
}

void usage(int argc, char **argv)
{
	fprintf(stderr, "Usage: %s <grid_rows/grid_cols> <pyramid_height> <sim_time> <temp_file> <power_file> <output_file>\n", argv[0]);
	fprintf(stderr, "\t<grid_rows/grid_cols>  - number of rows/cols in the grid (positive integer)\n");
	fprintf(stderr, "\t<pyramid_height> - pyramid heigh(positive integer)\n");
	fprintf(stderr, "\t<sim_time>   - number of iterations\n");
	fprintf(stderr, "\t<temp_file>  - name of the file containing the initial temperature values of each cell\n");
	fprintf(stderr, "\t<power_file> - name of the file containing the dissipated power values of each cell\n");
	fprintf(stderr, "\t<output_file> - name of the output file\n");
	exit(1);
}

int main(int argc, char** argv)
{
  printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);

    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    int size;
    int grid_rows,grid_cols;
    float *FilesavingTemp,*FilesavingPower,*MatrixOut; 
    char *tfile, *pfile, *ofile;

    int total_iterations = 60;
    int pyramid_height = 1; 

	if (argc != 7)
		usage(argc, argv);
	if((grid_rows = atoi(argv[1]))<=0||
	   (grid_cols = atoi(argv[1]))<=0||
       (pyramid_height = atoi(argv[2]))<=0||
       (total_iterations = atoi(argv[3]))<=0)
		usage(argc, argv);

	tfile=argv[4];
    pfile=argv[5];
    ofile=argv[6];

    size=grid_rows*grid_cols;


    # define EXPAND_RATE 2
    int borderCols = (pyramid_height)*EXPAND_RATE/2;
    int borderRows = (pyramid_height)*EXPAND_RATE/2;
    int smallBlockCol = BLOCK_SIZE-(pyramid_height)*EXPAND_RATE;
    int smallBlockRow = BLOCK_SIZE-(pyramid_height)*EXPAND_RATE;
    int blockCols = grid_cols/smallBlockCol+((grid_cols%smallBlockCol==0)?0:1);
    int blockRows = grid_rows/smallBlockRow+((grid_rows%smallBlockRow==0)?0:1);

    FilesavingTemp = (float *) malloc(size*sizeof(float));
    FilesavingPower = (float *) malloc(size*sizeof(float));
    MatrixOut = (float *) calloc (size, sizeof(float));

    if( !FilesavingPower || !FilesavingTemp || !MatrixOut)
        fatal("unable to allocate memory");

    printf("pyramidHeight: %d\ngridSize: [%d, %d]\nborder:[%d, %d]\nblockGrid:[%d, %d]\ntargetBlock:[%d, %d]\n",\
	pyramid_height, grid_cols, grid_rows, borderCols, borderRows, blockCols, blockRows, smallBlockCol, smallBlockRow);

    readinput(FilesavingTemp, grid_rows, grid_cols, tfile);
    readinput(FilesavingPower, grid_rows, grid_cols, pfile);

    float *MatrixTemp[2], *MatrixPower;
    MatrixTemp[0] = (float *)malloc(sizeof(float)*size);
    MatrixTemp[1] = (float *)malloc(sizeof(float)*size);
    memcpy(MatrixTemp[0], FilesavingTemp, sizeof(float)*size);

    MatrixPower = (float *)malloc(sizeof(float)*size);
    memcpy(MatrixPower, FilesavingPower, sizeof(float)*size);
    printf("Start computing the transient temperature\n");
    int ret = compute_tran_temp(MatrixPower,MatrixTemp,grid_cols,grid_rows, \
	 total_iterations,pyramid_height, blockCols, blockRows, borderCols, borderRows);
	printf("Ending simulation\n");
    memcpy(MatrixOut, MatrixTemp[ret], sizeof(float)*size);

    writeoutput(MatrixOut,grid_rows, grid_cols, ofile);

    free(MatrixPower);
    free(MatrixTemp[0]);
    free(MatrixTemp[1]);
    free(MatrixOut);
}

