float **kmeans_clustering(float **features,
                          int nfeatures,
                          int npoints,
                          int nclusters,
                          float threshold,
                          int *membership)
{
    int i, j, k;
    int loop = 0;
    int delta = 1;
    float **cluster_centres;
    int *new_centers_len;
    float **new_centers;

    cluster_centres = (float **) malloc(nclusters * sizeof(float *));
    cluster_centres[0] = (float *) malloc(nclusters * nfeatures * sizeof(float));
    for(i = 0; i < nclusters; i++)
        cluster_centres[i] = cluster_centres[0] + i * nfeatures;

    new_centers = (float **) malloc(nclusters * sizeof(float *));
    new_centers[0] = (float *) malloc(nclusters * nfeatures * sizeof(float));
    for(i = 0; i < nclusters; i++)
        new_centers[i] = new_centers[0] + i * nfeatures;

    new_centers_len = (int *) malloc(nclusters * sizeof(int));

    for(i = 0; i < npoints; i++)
        membership[i] = find_nearest_point(features[i], nfeatures, cluster_centres, nclusters);

    for(i = 0; i < nclusters; i++)
        for(j = 0; j < nfeatures; j++)
            new_centers[i][j] = 0.0;

    for(i = 0; i < npoints; i++) {
        int cluster_id = membership[i];
        for(j = 0; j < nfeatures; j++)
            new_centers[cluster_id][j] += features[i][j];
    }

    for(i = 0; i < nclusters; i++) {
        for(j = 0; j < nfeatures; j++)
            cluster_centres[i][j] = new_centers[i][j];
    }

    allocateMemory(npoints, nfeatures, nclusters, features);

    while(delta && loop < 100) {
        for(i = 0; i < nclusters; i++)
            new_centers_len[i] = 0;

        for(i = 0; i < nclusters; i++)
            for(j = 0; j < nfeatures; j++)
                new_centers[i][j] = 0.0;

        delta = kmeansCuda(features, nfeatures, npoints, nclusters,
                          membership, cluster_centres, new_centers_len, new_centers);

        for(i = 0; i < nclusters; i++) {
            if(new_centers_len[i] > 0) {
                for(j = 0; j < nfeatures; j++)
                    cluster_centres[i][j] = new_centers[i][j] / new_centers_len[i];
            }
        }

        loop++;
    }

    deallocateMemory();

    free(new_centers_len);
    free(new_centers[0]);
    free(new_centers);

    return cluster_centres;
}

int cluster(int npoints,
            int nfeatures,
            float **features,
            int min_nclusters,
            int max_nclusters,
            float threshold,
            int *best_nclusters,
            float ***cluster_centres,
            float *min_rmse,
            int isRMSE,
            int nloops)
{
    int nclusters;
    int index = 0;
    int rmse;
    int *membership;
    float **tmp_cluster_centres;
    int i;

    float min_rmse_ref = FLT_MAX;

    membership = (int*) malloc(npoints * sizeof(int));

    for(nclusters = min_nclusters; nclusters <= max_nclusters; nclusters++) {
        if(nclusters > npoints) break;

        allocateMemory(npoints, nfeatures, nclusters, features);

        for(i = 0; i < nloops; i++) {
            tmp_cluster_centres = kmeans_clustering(features,
                                                    nfeatures,
                                                    npoints,
                                                    nclusters,
                                                    threshold,
                                                    membership);

            if(*cluster_centres) {
                free((*cluster_centres)[0]);
                free(*cluster_centres);
            }
            *cluster_centres = tmp_cluster_centres;

            if(isRMSE) {
                rmse = rms_err(features, nfeatures, npoints, tmp_cluster_centres, nclusters);

                if(rmse < min_rmse_ref) {
                    min_rmse_ref = rmse;
                    *min_rmse = min_rmse_ref;
                    *best_nclusters = nclusters;
                    index = i;
                }
            }
        }

        deallocateMemory();
    }

    free(membership);

    return index;
}

float rms_err(float **feature,
              int nfeatures,
              int npoints,
              float **cluster_centres,
              int nclusters)
{
    int i;
    int nearest_cluster_index;
    float sum_euclid = 0.0;
    float ret;

    #pragma omp parallel for shared(feature, cluster_centres) \
                firstprivate(npoints, nfeatures, nclusters) \
                private(i, nearest_cluster_index) \
                schedule(static)
    for(i = 0; i < npoints; i++) {
        nearest_cluster_index = find_nearest_point(feature[i], nfeatures, cluster_centres, nclusters);
        sum_euclid += euclid_dist_2(feature[i], cluster_centres[nearest_cluster_index], nfeatures);
    }

    ret = sqrt(sum_euclid / npoints);
    return ret;
}

