void kernel_fin(fp *initvalu, int initvalu_offset_ecc, int initvalu_offset_Dyad, int initvalu_offset_SL, int initvalu_offset_Cyt, fp *parameter, fp *finavalu, fp JCaDyad, fp JCaSL, fp JCaCyt) {
