}

void master(fp timeinst, fp* initvalu, fp* parameter, fp* finavalu, fp* com, fp* d_initvalu, fp* d_finavalu, fp* d_params, fp* d_com) {
	int i;
	int initvalu_offset_ecc, initvalu_offset_Dyad, initvalu_offset_SL, initvalu_offset_Cyt;
	fp JCaDyad, JCaSL, JCaCyt;

	initvalu_offset_ecc = 0;
	initvalu_offset_Dyad = 46;
	initvalu_offset_SL = 61;
	initvalu_offset_Cyt = 76;

	ecc(timeinst, initvalu, initvalu_offset_ecc, parameter, 0, finavalu);

	JCaDyad = cam(timeinst, initvalu, initvalu_offset_Dyad, parameter, 0, finavalu, initvalu[35]*1e3);
	JCaSL = cam(timeinst, initvalu, initvalu_offset_SL, parameter, 5, finavalu, initvalu[36]*1e3);
	JCaCyt = cam(timeinst, initvalu, initvalu_offset_Cyt, parameter, 10, finavalu, initvalu[37]*1e3);

	com[0] = JCaDyad;
	com[1] = JCaSL;
	com[2] = JCaCyt;

	kernel_fin(initvalu, initvalu_offset_ecc, initvalu_offset_Dyad, initvalu_offset_SL, initvalu_offset_Cyt, parameter, finavalu, com[0], com[1], com[2]);

	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){
			finavalu[i] = 0.0001;
		}
		else if (isinf(finavalu[i]) == 1){
			finavalu[i] = 0.0001;
		}
