int maximum(int a, int b, int c) {
    int k;
    if(a <= b)
        k = b;
    else 
        k = a;

    if(k <= c)
        return(c);
    else
        return(k);
}

void needle_openmp_shared_1(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    int bx;
    for(bx = 0; bx <= i - 1; bx++) {
        int b_index_x = bx;
        int b_index_y = i - 1 - bx;

        int base_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

        int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
        int ref[BLOCK_SIZE][BLOCK_SIZE];

#pragma omp parallel
        {
            int tx = omp_get_thread_num();
            int num_threads = omp_get_num_threads();

            if(num_threads != BLOCK_SIZE) {
                if(tx == 0) {
                    fprintf(stderr, "Error: number of threads must equal BLOCK_SIZE (%d)\n", BLOCK_SIZE);
                }
                omp_end_parallel();
                return;
            }

            if(tx == 0)
                temp[tx][0] = matrix_cuda[base_index];

            for(int ty = 0; ty < BLOCK_SIZE; ty++)
                ref[ty][tx] = referrence[base_index + tx + cols * ty + cols + 1];

#pragma omp barrier

            temp[tx + 1][0] = matrix_cuda[base_index + cols + tx * cols];

#pragma omp barrier

            temp[0][tx + 1] = matrix_cuda[base_index + tx + 1];

#pragma omp barrier

            for(int m = 0; m < BLOCK_SIZE; m++) {
                if(tx <= m) {
                    int t_index_x = tx + 1;
                    int t_index_y = m - tx + 1;

                    temp[t_index_y][t_index_x] = maximum(
                        temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                        temp[t_index_y][t_index_x-1] - penalty,
                        temp[t_index_y-1][t_index_x] - penalty);
                }

#pragma omp barrier
            }

            for(int m = BLOCK_SIZE - 2; m >= 0; m--) {
                if(tx <= m) {
                    int t_index_x = tx + BLOCK_SIZE - m;
                    int t_index_y = BLOCK_SIZE - tx;

                    temp[t_index_y][t_index_x] = maximum(
                        temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                        temp[t_index_y][t_index_x-1] - penalty,
                        temp[t_index_y-1][t_index_x] - penalty);
                }

#pragma omp barrier
            }

            for(int ty = 0; ty < BLOCK_SIZE; ty++)
                matrix_cuda[base_index + tx + ty * cols + cols + 1] = temp[ty+1][tx+1];
        }
    }
}

void needle_openmp_shared_2(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    int bx;
    for(bx = 0; bx <= block_width - i - 1; bx++) {
        int b_index_x = bx + block_width - i;
        int b_index_y = block_width - bx - 1;

        int base_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

        int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
        int ref[BLOCK_SIZE][BLOCK_SIZE];

#pragma omp parallel
        {
            int tx = omp_get_thread_num();
            int num_threads = omp_get_num_threads();

            if(num_threads != BLOCK_SIZE) {
                if(tx == 0) {
                    fprintf(stderr, "Error: number of threads must equal BLOCK_SIZE (%d)\n", BLOCK_SIZE);
                }
                omp_end_parallel();
                return;
            }

            for(int ty = 0; ty < BLOCK_SIZE; ty++)
                ref[ty][tx] = referrence[base_index + tx + cols * ty + cols + 1];

#pragma omp barrier

            if(tx == 0)
                temp[tx][0] = matrix_cuda[base_index];

            temp[tx + 1][0] = matrix_cuda[base_index + cols + tx * cols];

#pragma omp barrier

            temp[0][tx + 1] = matrix_cuda[base_index + tx + 1];

#pragma omp barrier

            for(int m = 0; m < BLOCK_SIZE; m++) {
                if(tx <= m) {
                    int t_index_x = tx + 1;
                    int t_index_y = m - tx + 1;

                    temp[t_index_y][t_index_x] = maximum(
                        temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                        temp[t_index_y][t_index_x-1] - penalty,
                        temp[t_index_y-1][t_index_x] - penalty);
                }

#pragma omp barrier
            }

            for(int m = BLOCK_SIZE - 2; m >= 0; m--) {
                if(tx <= m) {
                    int t_index_x = tx + BLOCK_SIZE - m;
                    int t_index_y = BLOCK_SIZE - tx;

                    temp[t_index_y][t_index_x] = maximum(
                        temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                        temp[t_index_y][t_index_x-1] - penalty,
                        temp[t_index_y-1][t_index_x] - penalty);
                }

#pragma omp barrier
            }

            for(int ty = 0; ty < BLOCK_SIZE; ty++)
                matrix_cuda[base_index + tx + ty * cols + cols + 1] = temp[ty+1][tx+1];
        }
    }
}

