void needle_openmp_shared_1(int* referrence, int* matrix, int cols, int penalty, int i, int block_width) {
  int bx;

  #pragma omp parallel for
  for(bx = 1; bx <= block_width; bx++) {
    int b_index_x = bx;
    int b_index_y = i - 1 - bx;

    int base_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    int index = base_index + cols + 1;
    int index_n = base_index + 1;
    int index_w = base_index + cols;
    int index_nw = base_index;

    int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
    int ref[BLOCK_SIZE][BLOCK_SIZE];

    temp[0][0] = matrix[index_nw];

    for(int ty = 0; ty < BLOCK_SIZE; ty++)
      ref[ty][0] = referrence[index + cols * ty];

    temp[1][0] = matrix[index_w + cols * 0];
    temp[0][1] = matrix[index_n];

    #pragma omp barrier

    for(int m = 0; m < BLOCK_SIZE; m++) {
      for(int tx = 0; tx <= m; tx++) {
        int t_index_x = tx + 1;
        int t_index_y = m - tx + 1;

        temp[t_index_y][t_index_x] = maximum(
          temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
          temp[t_index_y][t_index_x-1] - penalty,
          temp[t_index_y-1][t_index_x] - penalty);
      }
      #pragma omp barrier
    }

    for(int m = BLOCK_SIZE - 2; m >= 0; m--) {
      for(int tx = 0; tx <= m; tx++) {
        int t_index_x = tx + BLOCK_SIZE - m;
        int t_index_y = BLOCK_SIZE - tx;

        temp[t_index_y][t_index_x] = maximum(
          temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
          temp[t_index_y][t_index_x-1] - penalty,
          temp[t_index_y-1][t_index_x] - penalty);
      }
      #pragma omp barrier
    }

    for(int ty = 0; ty < BLOCK_SIZE; ty++)
      matrix[index + ty * cols] = temp[ty+1][1];
  }
}

void needle_openmp_shared_2(int* referrence, int* matrix, int cols, int penalty, int i, int block_width) {
  int bx;

  #pragma omp parallel for
  for(bx = 1; bx <= block_width - 1; bx++) {
    int b_index_x = bx + block_width - i;
    int b_index_y = block_width - bx - 1;

    int base_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    int index = base_index + cols + 1;
    int index_n = base_index + 1;
    int index_w = base_index + cols;
    int index_nw = base_index;

    int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
    int ref[BLOCK_SIZE][BLOCK_SIZE];

    for(int ty = 0; ty < BLOCK_SIZE; ty++)
      ref[ty][0] = referrence[index + cols * ty];

    temp[0][0] = matrix[index_nw];
    temp[1][0] = matrix[index_w + cols * 0];
    temp[0][1] = matrix[index_n];

    #pragma omp barrier

    for(int m = 0; m < BLOCK_SIZE; m++) {
      for(int tx = 0; tx <= m; tx++) {
        int t_index_x = tx + 1;
        int t_index_y = m - tx + 1;

        temp[t_index_y][t_index_x] = maximum(
          temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
          temp[t_index_y][t_index_x-1] - penalty,
          temp[t_index_y-1][t_index_x] - penalty);
      }
      #pragma omp barrier
    }

    for(int m = BLOCK_SIZE - 2; m >= 0; m--) {
      for(int tx = 0; tx <= m; tx++) {
        int t_index_x = tx + BLOCK_SIZE - m;
        int t_index_y = BLOCK_SIZE - tx;

        temp[t_index_y][t_index_x] = maximum(
          temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
          temp[t_index_y][t_index_x-1] - penalty,
          temp[t_index_y-1][t_index_x] - penalty);
      }
      #pragma omp barrier
    }

    for(int ty = 0; ty < BLOCK_SIZE; ty++)
      matrix[index + ty * cols] = temp[ty+1][1];
  }
}

