using namespace std;

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define PROFILE
#define CACHE_LINE 512

typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

struct pkmedian_arg_t
{
  Points* points;
  long kmin;
  long kmax;
  long* kfinal;
  int pid;
  pthread_barrier_t* barrier;
};

class PStream {
public:
  virtual size_t read( float* dest, int dim, int num ) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {
  }
};

class SimStream : public PStream {
public:
  SimStream(long n_ ) {
    n = n_;
  }
  size_t read( float* dest, int dim, int num ) {
    size_t count = 0;
    for( int i = 0; i < num && n > 0; i++ ) {
      for( int k = 0; k < dim; k++ ) {
        dest[i*dim + k] = lrand48()/((float)INT_MAX);
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() {
    return 0;
  }
  int feof() {
    return n <= 0;
  }
  ~SimStream() {
  }
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char* filename) {
    fp = fopen( filename, "rb");
    if( fp == NULL ) {
      fprintf(stderr,"error opening file %s\n.",filename);
      exit(1);
    }
  }
  size_t read( float* dest, int dim, int num ) {
    return std::fread(dest, sizeof(float)*dim, num, fp);
  }
  int ferror() {
    return std::ferror(fp);
  }
  int feof() {
    return std::feof(fp);
  }
  ~FileStream() {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE* fp;
};

static bool *switch_membership;
static bool *is_center;
static int  *center_table;
static int nproc;
bool isCoordChanged;

double serial_t;
double cpu_to_gpu_t;
double gpu_to_cpu_t;
double alloc_t;
double kernel_t;
double free_t;

#ifdef PROFILE
double time_local_search;
double time_speedy;
double time_select_feasible;
double time_gain;
double time_shuffle;
double time_gain_dist;
double time_gain_init;
#endif

float *coord_h;

static int iter = 0;

float d_dist(int p1, int p2, int num, int dim, float *coord_d)
{
  float retval = 0.0;
  for(int i = 0; i < dim; i++){
    float tmp = coord_d[(i*num)+p1] - coord_d[(i*num)+p2];
    retval += tmp * tmp;
  }
  return retval;
}

void kernel_compute_cost(int num, int dim, long x, Point *p, int K, int stride,
                         float *coord_d, float *work_mem_d, int *center_table_d, bool *switch_membership_d)
{
  #pragma omp parallel for
  for(int tid = 0; tid < num; tid++)
  {
    float *lower = &work_mem_d[tid*stride];

    float x_cost = d_dist(tid, x, num, dim, coord_d) * p[tid].weight;

    if ( x_cost < p[tid].cost )
    {
      switch_membership_d[tid] = 1;
      lower[K] += x_cost - p[tid].cost;
    }
    else
    {
      lower[center_table_d[p[tid].assign]] += p[tid].cost - x_cost;
    }
  }
}

void allocDevMem(int num, int dim)
{
  center_table = (int*)malloc(num * sizeof(int));
  switch_membership = (bool*)malloc(num * sizeof(bool));
  coord_h = (float*)malloc(num * dim * sizeof(float));
}

void allocHostMem(int num, int dim)
{
  coord_h = (float*)malloc(num * dim * sizeof(float));
}

void freeDevMem()
{
  free(center_table);
  free(switch_membership);
  free(coord_h);
}

void freeHostMem()
{
  free(coord_h);
}

float dist(Point p1, Point p2, int dim)
{
  int i;
  float result=0.0;
  for (i=0;i<dim;i++)
    result += (p1.coord[i] - p2.coord[i])*(p1.coord[i] - p2.coord[i]);
  return(result);
}

float pgain( long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, bool *switch_membership, bool isCoordChanged,
             double *serial_t, double *cpu_to_gpu_t, double *gpu_to_cpu_t, double *alloc_t, double *kernel_t, double *free_t)
{
  double tmp_t;
  double start_time, stop_time;

  start_time = omp_get_wtime();

  int stride = *numcenters + 1;
  int K = *numcenters;
  int num = points->num;
  int dim = points->dim;
  int nThread = num;

  float *work_mem_h = (float*)malloc(stride * (nThread + 1) * sizeof(float));

  if(iter == 0)
  {
    allocHostMem(num, dim);
  }

  int count = 0;
  for( int i=0; i<num; i++)
  {
    if( is_center[i] )
    {
      center_table[i] = count++;
    }
  }

  if(isCoordChanged || iter == 0)
  {
    for(int i=0; i<dim; i++)
    {
      for(int j=0; j<num; j++)
      {
        coord_h[(num*i)+j] = points->p[j].coord[i];
      }
    }
  }

  stop_time = omp_get_wtime();
  *serial_t += (stop_time - start_time);

  start_time = omp_get_wtime();

  float *work_mem_d = (float*)malloc(stride * (nThread + 1) * sizeof(float));

  if( iter == 0 )
  {
    allocDevMem(num, dim);
  }

  stop_time = omp_get_wtime();
  *alloc_t += (stop_time - start_time);

  start_time = omp_get_wtime();

  if(isCoordChanged || iter == 0)
  {
    memcpy(coord_h, coord_h, num * dim * sizeof(float));
  }
  memcpy(center_table, center_table, num * sizeof(int));

  memset((void*) switch_membership, 0, num * sizeof(bool));
  memset((void*) work_mem_d, 0, stride * (nThread + 1) * sizeof(float));

  stop_time = omp_get_wtime();
  *cpu_to_gpu_t += (stop_time - start_time);

  start_time = omp_get_wtime();

  kernel_compute_cost(num, dim, x, points->p, K, stride, coord_h, work_mem_d, center_table, switch_membership);

  stop_time = omp_get_wtime();
  *kernel_t += (stop_time - start_time);

  start_time = omp_get_wtime();

  memcpy(work_mem_h, work_mem_d, stride * (nThread + 1) * sizeof(float));
  memcpy(switch_membership, switch_membership, num * sizeof(bool));

  stop_time = omp_get_wtime();
  *gpu_to_cpu_t += (stop_time - start_time);

  start_time = omp_get_wtime();

  int number_of_centers_to_close = 0;
  float gl_cost_of_opening_x = z;
  float *gl_lower = &work_mem_h[stride * nThread];

  for(int i=0; i < num; i++)
  {
    if( is_center[i] )
    {
      float low = z;
      for( int j = 0; j < num; j++ )
      {
        low += work_mem_h[j*stride + center_table[i]];
      }

      gl_lower[center_table[i]] = low;

      if ( low > 0 )
      {
        ++number_of_centers_to_close;
        work_mem_h[i*stride+K] -= low;
      }
    }
    gl_cost_of_opening_x += work_mem_h[i*stride+K];
  }

  if ( gl_cost_of_opening_x < 0 )
  {
    for(int i = 0; i < num; i++)
    {
      bool close_center = gl_lower[center_table[points->p[i].assign]] > 0;
      if ( switch_membership[i] || close_center )
      {
        points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
        points->p[i].assign = x;
      }
    }

    for(int i = 0; i < num; i++)
    {
      if( is_center[i] && gl_lower[center_table[i]] > 0 )
      {
        is_center[i] = false;
      }
    }

    if( x >= 0 && x < num)
    {
      is_center[x] = true;
    }
    *numcenters = *numcenters + 1 - number_of_centers_to_close;
  }
  else
  {
    gl_cost_of_opening_x = 0;
  }

  free(work_mem_h);
  free(work_mem_d);

  stop_time = omp_get_wtime();
  *serial_t += (stop_time - start_time);

  start_time = omp_get_wtime();

  free(work_mem_d);

  stop_time = omp_get_wtime();
  *free_t += (stop_time - start_time);

  iter++;
  return -gl_cost_of_opening_x;
}

